    systemPrompt: RETRIEVE_LENS_SYSTEM(lens),
    userPrompt: RETRIEVE_LENS_USER(lens, ctx.topic, subQuestions),
    model: "sonnet",
    outputFile: `${ctx.outputDir}/phase03_retrieve_${lens}.md`,
    tools: ["web_search"],
    effort: "high"
